    17‚Üí
    18‚Üíexport class TelegramService {
    19‚Üí    public bot: Bot<BotContext>;
    20‚Üí
    21‚Üí    constructor(private server: FastifyInstance, token: string) {
    22‚Üí        this.bot = new Bot<BotContext>(token);
    23‚Üí
    24‚Üí        // Init Claude chat (graceful ‚Äî logs warning if no API key)
    25‚Üí        const claudeReady = initClaudeChat();
    26‚Üí        if (claudeReady) {
    27‚Üí            server.log.info('Claude AI chat enabled for Telegram bot');
    28‚Üí        } else {
    29‚Üí            server.log.warn('ANTHROPIC_API_KEY not set ‚Äî AI chat disabled, using FAQ fallback');
    30‚Üí        }
    31‚Üí
    32‚Üí        this.registerHandlers();
    33‚Üí    }
    34‚Üí
    35‚Üí    private registerHandlers() {
    36‚Üí        // Error boundary
    37‚Üí        this.bot.catch(errorMiddleware(this.server));
    38‚Üí
    39‚Üí        // Global middleware ‚Äî logs ALL inbound messages before handlers
    40‚Üí        this.bot.use(chatLogMiddleware(this.server));
    41‚Üí
    42‚Üí        // Command handlers (order matters ‚Äî specific before generic)
    43‚Üí        this.bot.use(startHandler(this.server));
    44‚Üí        this.bot.use(helpHandler(this.server));
    45‚Üí        this.bot.use(aboutHandler(this.server));
    46‚Üí        this.bot.use(statusHandler(this.server));
    47‚Üí        this.bot.use(verifyHandler(this.server));
    48‚Üí        this.bot.use(registerHandler(this.server));
    49‚Üí        this.bot.use(questsHandler(this.server));
    50‚Üí        this.bot.use(createHandler(this.server));
    51‚Üí        this.bot.use(waitlistHandler(this.server));
    52‚Üí
    53‚Üí        // Fallback must be last ‚Äî catches unmatched messages + active sessions
    54‚Üí        this.bot.use(fallbackHandler(this.server));
    55‚Üí    }
    56‚Üí
    57‚Üí    public async startPolling() {
    58‚Üí        // Ensure no webhook is set ‚Äî otherwise Telegram sends updates only to webhook URL
    59‚Üí        // and getUpdates (polling) receives nothing. Common cause of "bot works in dev, not in prod".
    60‚Üí        try {
