    74‚Üí            { command: 'verify', description: 'Verify agent or quest ownership' },
    75‚Üí            { command: 'help', description: 'Show available commands' },
    76‚Üí            { command: 'about', description: 'Learn about ClawQuest' },
    77‚Üí        ]);
    78‚Üí
    79‚Üí        console.log('ü§ñ Telegram Bot starting in Polling mode...');
    80‚Üí        await this.bot.start({
