     1‚Üí/**
     2‚Üí * Completion-time social action verification.
     3‚Üí * Confirms user actually performed the task (follow, like, repost, post, join, etc.)
     4‚Üí * Separate from social-validator.ts which only checks target existence at creation time.
     5‚Üí */
     6‚Üíimport { PrismaClient } from '@prisma/client'
     7‚Üíimport { ensureFreshToken, getTweet, checkFollowing, lookupUserByUsername } from '../x/x-rest-client'
     8‚Üíimport { fetchTweetById, checkUserFollows, fetchTweetForQuoteVerify } from '../x/x-rapidapi-client'
     9‚Üíimport { extractTweetId, normaliseHandle } from '../x/x-utils'
    10‚Üíimport { getGuildMember, getUserGuildMember } from '../discord/discord-rest-client'
    11‚Üíimport { validateSocialTarget, type SocialValidationResult } from './social-validator'
    12‚Üí
    13‚Üíexport interface VerificationContext {
    14‚Üí  userId: string
    15‚Üí  prisma: PrismaClient
    16‚Üí  // X identity
    17‚Üí  xId?: string | null
    18‚Üí  xHandle?: string | null
    19‚Üí  xAccessToken?: string | null
    20‚Üí  xRefreshToken?: string | null
    21‚Üí  xTokenExpiry?: Date | null
    22‚Üí  // Discord identity
    23‚Üí  discordId?: string | null
    24‚Üí  discordAccessToken?: string | null
    25‚Üí  // Telegram identity
    26‚Üí  telegramId?: string | null
    27‚Üí  // Proof URLs for post/quote_post (map of taskIndex ‚Üí URL)
    28‚Üí  proofUrls?: Record<number, string>
    29‚Üí  // Task params from quest definition
    30‚Üí  params?: Record<string, string>
    31‚Üí  // Telegram bot token
    32‚Üí  telegramBotToken?: string
    33‚Üí}
    34‚Üí
    35‚Üí// ‚îÄ‚îÄ X Verification ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
    36‚Üí
    37‚Üíasync function verifyXAction(
    38‚Üí  actionType: string, ctx: VerificationContext, taskIndex: number,
    39‚Üí): Promise<SocialValidationResult> {
    40‚Üí  // post/quote_post can use RapidAPI as fallback ‚Äî they verify via proof URL, not user-specific API calls
    41‚Üí  if (actionType === 'post' || actionType === 'quote_post') {
    42‚Üí    return verifyXPostWithFallback(actionType, ctx, taskIndex)
    43‚Üí  }
    44‚Üí
    45‚Üí  // like_post, follow_account, repost verify via RapidAPI using xHandle (no OAuth token needed)
    46‚Üí  if (!ctx.xHandle) return { valid: false, error: 'Link your X account to verify this task' }
    47‚Üí
    48‚Üí  // Support multiple param key conventions used by quest creators
    49‚Üí  const targetValue = ctx.params?.targetUrl || ctx.params?.postUrl || ctx.params?.accountHandle || ctx.params?.username || ''
    50‚Üí
    51‚Üí  switch (actionType) {
    52‚Üí    case 'follow_account': {
    53‚Üí      const targetHandle = targetValue.replace(/^@/, '').replace(/^https?:\/\/(x|twitter)\.com\//, '')
    54‚Üí      // Prefer OAuth path when user has linked X (official API); fallback to RapidAPI when no token
    55‚Üí      if (ctx.xId && (ctx.xAccessToken || ctx.xRefreshToken)) {
    56‚Üí        const token = await ensureFreshToken(
    57‚Üí          { id: ctx.userId, xAccessToken: ctx.xAccessToken, xRefreshToken: ctx.xRefreshToken, xTokenExpiry: ctx.xTokenExpiry },
    58‚Üí          ctx.prisma,
    59‚Üí        )
    60‚Üí        if (token) {
    61‚Üí          const targetXId = await lookupUserByUsername(token, targetHandle)
    62‚Üí          if (targetXId) {
    63‚Üí            const follows = await checkFollowing(token, ctx.xId, targetXId)
    64‚Üí            if (follows !== null) return follows ? { valid: true } : { valid: false, error: 'You are not following this account' }
    65‚Üí          }
    66‚Üí        }
    67‚Üí      }
    68‚Üí      // Fallback: RapidAPI (no OAuth). Requires xHandle.
    69‚Üí      if (!ctx.xHandle) return { valid: false, error: 'Follow verification unavailable ‚Äî link your X account to verify' }
    70‚Üí      const follows = await checkUserFollows(ctx.xHandle, targetHandle)
    71‚Üí      if (follows === null) return { valid: false, error: 'Follow verification unavailable ‚Äî try again later' }
    72‚Üí      return follows ? { valid: true } : { valid: false, error: 'You are not following this account' }
    73‚Üí    }
    74‚Üí    case 'like_post':
    75‚Üí      return { valid: false, error: 'Like verification coming soon ‚Äî please check back later' }
    76‚Üí    case 'repost':
    77‚Üí      return { valid: false, error: 'Repost verification coming soon ‚Äî please check back later' }
    78‚Üí    default:
    79‚Üí      return { valid: true }
    80‚Üí  }
    81‚Üí}
