    83‚Üí/**
    84‚Üí * Verify post/quote_post tasks via RapidAPI (no OAuth token needed).
    85‚Üí * Primary path: uses RapidAPI to fetch the proof tweet and checks author by xHandle.
    86‚Üí * Fallback: if no RapidAPI key, uses OAuth token (original behavior).
    87‚Üí */
    88‚Üíasync function verifyXPostWithFallback(
    89‚Üí  actionType: 'post' | 'quote_post', ctx: VerificationContext, taskIndex: number,
    90‚Üí): Promise<SocialValidationResult> {
    91‚Üí  const proofUrl = ctx.proofUrls?.[taskIndex]
    92‚Üí  if (!proofUrl) return { valid: false, error: 'Paste your tweet URL to verify' }
    93‚Üí  const proofTweetId = extractTweetId(proofUrl)
    94‚Üí  if (!proofTweetId) return { valid: false, error: 'Invalid tweet URL ‚Äî use format: https://x.com/.../status/...' }
    95‚Üí
    96‚Üí  const targetValue = ctx.params?.targetUrl || ctx.params?.postUrl || ctx.params?.accountHandle || ctx.params?.username || ''
    97‚Üí
    98‚Üí  // Path A: RapidAPI (no OAuth required)
    99‚Üí  const rapidApiKey = process.env.RAPID_API_KEY
   100‚Üí  if (rapidApiKey) {
   101‚Üí    if (actionType === 'quote_post') {
   102‚Üí      // Use /get-tweet endpoint for reliable author ID + quoted_status_id_str
   103‚Üí      const result = await fetchTweetForQuoteVerify(proofTweetId, rapidApiKey)
   104‚Üí      if (!result) return { valid: false, error: 'Tweet not found ‚Äî is it public?' }
   105‚Üí      if (ctx.xId && result.authorId && result.authorId !== ctx.xId) {
   106‚Üí        return { valid: false, error: 'This tweet was not posted by your linked X account' }
   107‚Üí      }
   108‚Üí      const targetTweetId = extractTweetId(targetValue)
   109‚Üí      if (targetTweetId && result.quotedStatusId !== targetTweetId) {
   110‚Üí        return { valid: false, error: 'This tweet does not quote the required post' }
   111‚Üí      }
   112‚Üí      return { valid: true }
   113‚Üí    }
   114‚Üí
   115‚Üí    // post: use fetchTweetById, verify author by xHandle or xId
   116‚Üí    const tweet = await fetchTweetById(proofTweetId, rapidApiKey)
   117‚Üí    if (!tweet) return { valid: false, error: 'Tweet not found ‚Äî is it public?' }
   118‚Üí    if (ctx.xHandle) {
   119‚Üí      if (normaliseHandle(tweet.author.screenName) !== normaliseHandle(ctx.xHandle)) {
   120‚Üí        return { valid: false, error: 'This tweet was not posted by your linked X account' }
   121‚Üí      }
   122‚Üí    } else if (ctx.xId && tweet.author.id && tweet.author.id !== ctx.xId) {
   123‚Üí      return { valid: false, error: 'This tweet was not posted by your linked X account' }
   124‚Üí    }
   125‚Üí    return { valid: true }
   126‚Üí  }
   127‚Üí
   128‚Üí  // Path B: OAuth fallback (original behavior)
   129‚Üí  if (!ctx.xId) return { valid: false, error: 'Link your X account to verify this task' }
   130‚Üí  const token = await ensureFreshToken(
   131‚Üí    { id: ctx.userId, xAccessToken: ctx.xAccessToken, xRefreshToken: ctx.xRefreshToken, xTokenExpiry: ctx.xTokenExpiry },
   132‚Üí    ctx.prisma,
   133‚Üí  )
   134‚Üí  if (!token) return { valid: false, error: 'X account token expired ‚Äî please re-link your X account' }
   135‚Üí  const tweet = await getTweet(token, proofTweetId)
   136‚Üí  if (!tweet) return { valid: false, error: 'Tweet not found ‚Äî is it public?' }
   137‚Üí  if (tweet.authorId !== ctx.xId) return { valid: false, error: 'This tweet was not posted by your linked X account' }
   138‚Üí  if (actionType === 'quote_post') {
   139‚Üí    const targetTweetId = extractTweetId(targetValue)
   140‚Üí    if (targetTweetId && tweet.quotedTweetId !== targetTweetId) {
   141‚Üí      return { valid: false, error: 'This tweet does not quote the required post' }
   142‚Üí    }
   143‚Üí  }
   144‚Üí  return { valid: true }
   145‚Üí}
   146‚Üí
   147‚Üí// ‚îÄ‚îÄ Discord Verification ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
   148‚Üí
   149‚Üíasync function verifyDiscordAction(
   150‚Üí  actionType: string, ctx: VerificationContext,
   151‚Üí): Promise<SocialValidationResult> {
   152‚Üí  if (!ctx.discordId) return { valid: false, error: 'Link your Discord account to verify this task' }
   153‚Üí
   154‚Üí  if (actionType === 'join_server') {
   155‚Üí    const guildId = ctx.params?.guildId
   156‚Üí    if (!guildId) return { valid: false, error: 'Quest task missing guildId ‚Äî contact quest creator' }
   157‚Üí
   158‚Üí    // Prefer OAuth user token (no bot needed)
   159‚Üí    if (ctx.discordAccessToken) {
   160‚Üí      const roles = await getUserGuildMember(ctx.discordAccessToken, guildId)
   161‚Üí      if (roles !== null) return { valid: true }
   162‚Üí    }
   163‚Üí    // Fallback to bot
   164‚Üí    const botRoles = await getGuildMember(guildId, ctx.discordId)
   165‚Üí    if (botRoles !== null) return { valid: true }
   166‚Üí
   167‚Üí    return { valid: false, error: 'You have not joined this Discord server' }
   168‚Üí  }
   169‚Üí
   170‚Üí  // verify_role: delegate to existing validateDiscordRole via validateSocialTarget
   171‚Üí  if (actionType === 'verify_role') {
   172‚Üí    return validateSocialTarget('discord', 'verify_role', '', undefined, {
   173‚Üí      discordId: ctx.discordId,
   174‚Üí      discordAccessToken: ctx.discordAccessToken,
   175‚Üí      params: ctx.params,
   176‚Üí    })
   177‚Üí  }
   178‚Üí
   179‚Üí  return { valid: true }
   180‚Üí}
   181‚Üí
   182‚Üí// ‚îÄ‚îÄ Telegram Verification ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
   183‚Üí
   184‚Üíasync function verifyTelegramAction(
   185‚Üí  actionType: string, ctx: VerificationContext,
   186‚Üí): Promise<SocialValidationResult> {
   187‚Üí  if (actionType !== 'join_channel') return { valid: true }
   188‚Üí  if (!ctx.telegramId) return { valid: false, error: 'Link your Telegram account to verify this task' }
   189‚Üí  if (!ctx.telegramBotToken) return { valid: false, error: 'Telegram verification unavailable' }
   190‚Üí
   191‚Üí  const channelUrl = ctx.params?.channelUrl || ctx.params?.targetUrl || ''
   192‚Üí  let chatId: string
   193‚Üí  const urlMatch = channelUrl.match(/t\.me\/([A-Za-z0-9_]+)/)
   194‚Üí  if (urlMatch) chatId = `@${urlMatch[1]}`
   195‚Üí  else if (channelUrl.startsWith('@')) chatId = channelUrl
   196‚Üí  else chatId = `@${channelUrl.replace(/^https?:\/\//, '')}`
   197‚Üí
   198‚Üí  try {
   199‚Üí    const res = await fetch(
   200‚Üí      `https://api.telegram.org/bot${ctx.telegramBotToken}/getChatMember?chat_id=${encodeURIComponent(chatId)}&user_id=${ctx.telegramId}`,
   201‚Üí      { signal: AbortSignal.timeout(8000) },
   202‚Üí    )
   203‚Üí
   204‚Üí    // Always parse body ‚Äî Telegram always returns JSON even for HTTP errors
   205‚Üí    const data = await res.json() as { ok: boolean; result?: { status: string }; description?: string; error_code?: number }
   206‚Üí
   207‚Üí    if (!data.ok) {
   208‚Üí      const desc = data.description ?? ''
   209‚Üí      console.error(`[Telegram] getChatMember failed for chatId=${chatId} userId=${ctx.telegramId}: ${res.status} ${desc}`)
   210‚Üí
   211‚Üí      if (desc.includes('CHAT_ADMIN_REQUIRED') || res.status === 403)
   212‚Üí        return { valid: false, error: 'Bot must be added as an admin of this channel' }
   213‚Üí      if (desc.includes('chat not found'))
   214‚Üí        return { valid: false, error: 'Channel not found ‚Äî verify the channel URL in the quest task' }
   215‚Üí      if (desc.includes('USER_ID_INVALID') || desc.includes('user not found'))
   216‚Üí        return { valid: false, error: 'Could not verify your Telegram account ‚Äî try unlinking and relinking' }
   217‚Üí
   218‚Üí      return { valid: false, error: `Telegram error: ${desc || 'Could not check membership'}` }
   219‚Üí    }
   220‚Üí
   221‚Üí    const joined = ['creator', 'administrator', 'member', 'restricted'].includes(data.result?.status ?? '')
   222‚Üí    return joined
   223‚Üí      ? { valid: true }
   224‚Üí      : { valid: false, error: 'You have not joined this channel' }
   225‚Üí  } catch {
   226‚Üí    return { valid: false, error: 'Telegram API unavailable ‚Äî try again later' }
   227‚Üí  }
   228‚Üí}
   229‚Üí
   230‚Üí// ‚îÄ‚îÄ Main Dispatcher ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
   231‚Üí
   232‚Üí/** Completion-time verification: did user actually perform this action? */
   233‚Üíexport async function verifySocialAction(
   234‚Üí  platform: string, actionType: string, taskIndex: number, ctx: VerificationContext,
   235‚Üí): Promise<SocialValidationResult> {
   236‚Üí  switch (platform) {
   237‚Üí    case 'x': return verifyXAction(actionType, ctx, taskIndex)
   238‚Üí    case 'discord': return verifyDiscordAction(actionType, ctx)
   239‚Üí    case 'telegram': return verifyTelegramAction(actionType, ctx)
   240‚Üí    default: return { valid: true }
   241‚Üí  }
   242‚Üí}
