     1‚Üíimport { Composer } from 'grammy';
     2‚Üíimport { FastifyInstance } from 'fastify';
     3‚Üíimport { BotContext } from '../types';
     4‚Üíimport { MSG } from '../content/messages';
     5‚Üíimport { registerSessions } from '../telegram.session';
     6‚Üí
     7‚Üíexport function registerHandler(server: FastifyInstance): Composer<BotContext> {
     8‚Üí    const composer = new Composer<BotContext>();
     9‚Üí
    10‚Üí    composer.command('register', async (ctx) => {
    11‚Üí        const tgId = ctx.from?.id;
    12‚Üí        if (!tgId) return ctx.reply(MSG.genericError);
    13‚Üí
    14‚Üí        registerSessions.set(tgId, { step: 'email' });
    15‚Üí        return ctx.reply(MSG.registerStart + '\n\n' + MSG.registerEmailPrompt);
    16‚Üí    });
    17‚Üí
    18‚Üí    return composer;
    19‚Üí}
    20‚Üí
    21‚Üí// Exported for use in fallback handler ‚Äî handles text input during registration flow
    22‚Üíexport async function handleRegisterInput(
    23‚Üí    server: FastifyInstance,
    24‚Üí    ctx: BotContext,
    25‚Üí    text: string
    26‚Üí): Promise<boolean> {
    27‚Üí    const tgId = ctx.from?.id;
    28‚Üí    if (!tgId) return false;
    29‚Üí
    30‚Üí    const session = registerSessions.get(tgId);
    31‚Üí    if (!session) return false;
    32‚Üí
    33‚Üí    if (session.step === 'email') {
    34‚Üí        const email = text.trim().toLowerCase();
    35‚Üí        session.email = email;
    36‚Üí        session.step = 'code';
    37‚Üí        registerSessions.set(tgId, session);
    38‚Üí        await ctx.reply(MSG.registerCodePrompt);
    39‚Üí        return true;
    40‚Üí    }
    41‚Üí
    42‚Üí    if (session.step === 'code') {
    43‚Üí        await handleAgentRegistration(server, ctx, session.email!, text.trim());
    44‚Üí        registerSessions.delete(tgId);
    45‚Üí        return true;
    46‚Üí    }
    47‚Üí
    48‚Üí    return false;
    49‚Üí}
    50‚Üí
    51‚Üíasync function handleAgentRegistration(
    52‚Üí    server: FastifyInstance,
    53‚Üí    ctx: BotContext,
    54‚Üí    email: string,
    55‚Üí    code: string
    56‚Üí) {
    57‚Üí    try {
    58‚Üí        // 1. Find user by email
    59‚Üí        const user = await server.prisma.user.findUnique({ where: { email } });
    60‚Üí        if (!user) {
    61‚Üí            return ctx.reply(MSG.registerNoUser);
    62‚Üí        }
    63‚Üí
    64‚Üí        // 2. Find agent by activation code + owner
    65‚Üí        const agent = await server.prisma.agent.findFirst({
    66‚Üí            where: { activationCode: code, ownerId: user.id },
    67‚Üí        });
    68‚Üí        if (!agent) {
    69‚Üí            return ctx.reply(MSG.registerBadCode);
    70‚Üí        }
    71‚Üí
    72‚Üí        // 3. Check if already linked
    73‚Üí        const existing = await server.prisma.telegramLink.findUnique({
    74‚Üí            where: { agentId: agent.id },
    75‚Üí        });
    76‚Üí        if (existing) {
    77‚Üí            return ctx.reply(MSG.registerAlreadyLinked);
    78‚Üí        }
    79‚Üí
    80‚Üí        // 4. Create TelegramLink
    81‚Üí        await server.prisma.telegramLink.create({
    82‚Üí            data: {
    83‚Üí                agentId: agent.id,
    84‚Üí                telegramId: BigInt(ctx.from?.id || 0),
    85‚Üí                username: ctx.from?.username,
    86‚Üí                firstName: ctx.from?.first_name,
    87‚Üí            },
    88‚Üí        });
    89‚Üí
    90‚Üí        // 5. Clear activation code
    91‚Üí        await server.prisma.agent.update({
    92‚Üí            where: { id: agent.id },
    93‚Üí            data: { activationCode: null },
    94‚Üí        });
    95‚Üí
    96‚Üí        return ctx.reply(MSG.registerSuccess(agent.agentname, agent.id));
    97‚Üí    } catch (error) {
    98‚Üí        server.log.error(error);
    99‚Üí        return ctx.reply(MSG.genericError);
   100‚Üí    }
   101‚Üí}
