     1‚Üíimport { Composer } from 'grammy';
     2‚Üíimport { FastifyInstance } from 'fastify';
     3‚Üíimport { BotContext } from '../types';
     4‚Üíimport { MSG } from '../content/messages';
     5‚Üíimport { linkAccountKeyboard, claimAgentKeyboard, claimQuestKeyboard } from '../keyboards/menus';
     6‚Üíimport { mainReplyKeyboard } from '../keyboards/reply-keyboard';
     7‚Üíimport { handleWaitlistJoin, handleWaitlistJoinByToken } from './waitlist.handler';
     8‚Üí
     9‚Üíexport function startHandler(server: FastifyInstance): Composer<BotContext> {
    10‚Üí    const composer = new Composer<BotContext>();
    11‚Üí
    12‚Üí    composer.command('start', async (ctx) => {
    13‚Üí        const payload = ctx.match;
    14‚Üí
    15‚Üí        if (!payload) {
    16‚Üí            return handleBareStart(server, ctx);
    17‚Üí        }
    18‚Üí
    19‚Üí        // Waitlist join: ?start=waitlist or ?start=ref_<code>
    20‚Üí        if (payload === 'waitlist') {
    21‚Üí            return handleWaitlistJoin(server, ctx);
    22‚Üí        }
    23‚Üí
    24‚Üí        if (payload.startsWith('ref_')) {
    25‚Üí            const referralCode = payload.slice(4); // strip "ref_" prefix
    26‚Üí            return handleWaitlistJoin(server, ctx, referralCode);
    27‚Üí        }
    28‚Üí
    29‚Üí        // Web-initiated join: wl_<accessToken> ‚Äî links pending entry to Telegram user
    30‚Üí        if (payload.startsWith('wl_')) {
    31‚Üí            const accessToken = payload.slice(3);
    32‚Üí            return handleWaitlistJoinByToken(server, ctx, accessToken);
    33‚Üí        }
    34‚Üí
    35‚Üí        // Token prefix is the routing key ‚Äî no wrapper needed
    36‚Üí        if (payload.startsWith('agent_')) {
    37‚Üí            return handleVerifyDeeplink(server, ctx, payload);
    38‚Üí        }
    39‚Üí
    40‚Üí        if (payload.startsWith('quest_')) {
    41‚Üí            return handleQuestClaimDeeplink(server, ctx, payload);
    42‚Üí        }
    43‚Üí
    44‚Üí        // Legacy backward compatibility: old deeplinks used verify_ wrapper prefix
    45‚Üí        if (payload.startsWith('verify_')) {
    46‚Üí            const rawToken = payload.slice(7); // strip "verify_" prefix ‚Üí raw hex
    47‚Üí            return handleVerifyDeeplink(server, ctx, rawToken);
    48‚Üí        }
    49‚Üí
    50‚Üí        // Treat anything else as activation code
    51‚Üí        return handleActivationCode(server, ctx, payload);
    52‚Üí    });
    53‚Üí
    54‚Üí    return composer;
    55‚Üí}
    56‚Üí
    57‚Üíasync function handleBareStart(server: FastifyInstance, ctx: BotContext) {
    58‚Üí    const tgId = ctx.from?.id;
    59‚Üí    if (!tgId) {
    60‚Üí        return ctx.reply(MSG.welcome, { reply_markup: mainReplyKeyboard() });
    61‚Üí    }
    62‚Üí
    63‚Üí    try {
    64‚Üí        // Check if user has a linked account via telegramId on User model
    65‚Üí        const user = await server.prisma.user.findFirst({
    66‚Üí            where: { telegramId: String(tgId) },
    67‚Üí            select: { displayName: true, email: true },
    68‚Üí        });
    69‚Üí
    70‚Üí        if (user) {
    71‚Üí            const name = user.displayName || user.email || 'there';
    72‚Üí            return ctx.reply(MSG.welcomeBack(name), { reply_markup: mainReplyKeyboard() });
    73‚Üí        }
    74‚Üí
    75‚Üí        // Also check TelegramLink (agent ownership)
    76‚Üí        const link = await server.prisma.telegramLink.findFirst({
    77‚Üí            where: { telegramId: BigInt(tgId) },
    78‚Üí            select: { firstName: true },
    79‚Üí        });
    80‚Üí
    81‚Üí        if (link) {
    82‚Üí            const name = link.firstName || 'there';
