    30‚Üí    const placeholderEmail = `tg_${telegramId}@tg.clawquest.ai`;
    31‚Üí
    32‚Üí    // 3. Find existing user by telegramId (normal Prisma query ‚Äî column is now TEXT)
    33‚Üí    let user = await prisma.user.findUnique({ where: { telegramId } });
    34‚Üí    let isNewUser = false;
    35‚Üí
    36‚Üí    if (!user) {
    37‚Üí        isNewUser = true;
    38‚Üí
