    40‚Üí        const { data: supabaseUser, error: createError } = await supabaseAdmin.auth.admin.createUser({
    41‚Üí            email: placeholderEmail,
    42‚Üí            email_confirm: true,
    43‚Üí            user_metadata: {
    44‚Üí                telegramId: claims.telegramId,
    45‚Üí                telegram_username: claims.username,
    46‚Üí                provider: 'telegram',
    47‚Üí                full_name: claims.name,
    48‚Üí                avatar_url: claims.picture,
    49‚Üí            },
    50‚Üí        });
