    68‚Üí                    create: {
    69‚Üí                        supabaseId: sessionUser.user.id,
    70‚Üí                        email: placeholderEmail,
    71‚Üí                        username: claims.username ?? `tg_${claims.telegramId}`,
    72‚Üí                        displayName: claims.name ?? null,
    73‚Üí                        telegramId,
    74‚Üí                        telegramUsername: claims.username ?? null,
    75‚Üí                    },
    76‚Üí                });
    77‚Üí
    78‚Üí                // Short-circuit: we already have the session
    79‚Üí                const linkedAgents = await autoLinkAgents(prisma, telegramId, user.id);
    80‚Üí                await linkWaitlistEntry(prisma, telegramId, user.id);
    81‚Üí                return {
    82‚Üí                    session,
    83‚Üí                    user: {
    84‚Üí                        id: user.id,
    85‚Üí                        email: user.email,
    86‚Üí                        username: user.username,
    87‚Üí                        telegramId: user.telegramId!,
    88‚Üí                        telegramUsername: user.telegramUsername,
    89‚Üí                    },
    90‚Üí                    isNewUser: true,
    91‚Üí                    linkedAgents,
    92‚Üí                };
