    95‚Üí            }
    96‚Üí        } else {
    97‚Üí            // Upsert Prisma user to handle concurrent first-login race
    98‚Üí            user = await prisma.user.upsert({
    99‚Üí                where: { telegramId },
   100‚Üí                update: { supabaseId: supabaseUser.user.id },
   101‚Üí                create: {
   102‚Üí                    supabaseId: supabaseUser.user.id,
   103‚Üí                    email: placeholderEmail,
   104‚Üí                    username: claims.username ?? `tg_${claims.telegramId}`,
   105‚Üí                    displayName: claims.name ?? null,
   106‚Üí                    telegramId,
   107‚Üí                    telegramUsername: claims.username ?? null,
   108‚Üí                },
   109‚Üí            });
   110‚Üí        }
