   115‚Üí                where: { id: user.id },
   116‚Üí                data: { telegramUsername: claims.username },
   117‚Üí            });
   118‚Üí        }
   119‚Üí    }
   120‚Üí
   121‚Üí    // 4. Auto-link agents via TelegramLink matching (TelegramLink.telegramId is still BigInt)
   122‚Üí    const linkedAgents = await autoLinkAgents(prisma, telegramId, user.id);
