   130‚Üí    return {
   131‚Üí        session,
   132‚Üí        user: {
   133‚Üí            id: user.id,
   134‚Üí            email: user.email,
   135‚Üí            username: user.username,
   136‚Üí            telegramId: user.telegramId!,
   137‚Üí            telegramUsername: user.telegramUsername,
   138‚Üí        },
   139‚Üí        isNewUser,
   140‚Üí        linkedAgents,
   141‚Üí    };
   142‚Üí}
