   147‚Üíexport async function handleTelegramLink(params: {
   148‚Üí    code: string;
   149‚Üí    codeVerifier: string;
   150‚Üí    redirectUri: string;
   151‚Üí    userId: string;
   152‚Üí    prisma: PrismaClient;
   153‚Üí}): Promise<{ user: { id: string; email: string; telegramId: string | null; telegramUsername: string | null }; linkedAgents: string[] }> {
   154‚Üí    const { code, codeVerifier, redirectUri, userId, prisma } = params;
   155‚Üí
   156‚Üí    // 1. Exchange + verify
   157‚Üí    const tokens = await exchangeTelegramCode({ code, codeVerifier, redirectUri });
   158‚Üí    const claims = await verifyTelegramIdToken(tokens.id_token);
   159‚Üí    const telegramId = claims.telegramId;
   160‚Üí
   161‚Üí    // 2. Check telegramId not already linked to another user
   162‚Üí    const existing = await prisma.user.findUnique({ where: { telegramId } });
   163‚Üí    if (existing && existing.id !== userId) {
   164‚Üí        throw new Error('This Telegram account is already linked to another user');
   165‚Üí    }
   166‚Üí
   167‚Üí    // 3. Update user with Telegram info
   168‚Üí    const user = await prisma.user.update({
   169‚Üí        where: { id: userId },
   170‚Üí        data: {
   171‚Üí            telegramId,
   172‚Üí            telegramUsername: claims.username ?? null,
   173‚Üí        },
   174‚Üí    });
   175‚Üí
   176‚Üí    // 4. Auto-link agents
   177‚Üí    const linkedAgents = await autoLinkAgents(prisma, telegramId, userId);
   178‚Üí
   179‚Üí    // 5. Link waitlist entry if this Telegram was on the waitlist before linking
   180‚Üí    await linkWaitlistEntry(prisma, telegramId, userId);
