   182‚Üí    return {
   183‚Üí        user: {
   184‚Üí            id: user.id,
   185‚Üí            email: user.email,
   186‚Üí            telegramId: user.telegramId,
   187‚Üí            telegramUsername: user.telegramUsername,
   188‚Üí        },
   189‚Üí        linkedAgents,
   190‚Üí    };
   191‚Üí}
