   193‚Üí/**
   194‚Üí * Link a WaitlistEntry to a User account when the user connects their Telegram.
   195‚Üí * Matches by telegramId (BigInt). Safe no-op if no entry exists or already linked.
   196‚Üí */
   197‚Üíasync function linkWaitlistEntry(prisma: PrismaClient, telegramId: string, userId: string): Promise<void> {
   198‚Üí    const PG_BIGINT_MAX = BigInt('9223372036854775807');
   199‚Üí    let tgBigInt: bigint;
   200‚Üí    try {
   201‚Üí        tgBigInt = BigInt(telegramId);
   202‚Üí        if (tgBigInt < 0 || tgBigInt > PG_BIGINT_MAX) return;
   203‚Üí    } catch {
   204‚Üí        return;
   205‚Üí    }
   206‚Üí
   207‚Üí    const entry = await prisma.waitlistEntry.findUnique({
   208‚Üí        where: { telegramId: tgBigInt },
   209‚Üí        select: { id: true, userId: true },
   210‚Üí    });
   211‚Üí
   212‚Üí    // No entry, or already linked to this user ‚Äî nothing to do
   213‚Üí    if (!entry || entry.userId === userId) return;
   214‚Üí
   215‚Üí    // Already linked to a different user ‚Äî do not overwrite
   216‚Üí    if (entry.userId && entry.userId !== userId) return;
   217‚Üí
   218‚Üí    await prisma.waitlistEntry.update({
   219‚Üí        where: { id: entry.id },
   220‚Üí        data: { userId },
   221‚Üí    });
   222‚Üí}
   223‚Üí
   224‚Üí/**
   225‚Üí * Find unowned agents with TelegramLink matching this telegramId and claim them in batch.
   226‚Üí * TelegramLink.telegramId is BigInt ‚Äî if the ID exceeds bigint range, no rows can exist, so skip.
   227‚Üí */
   228‚Üíasync function autoLinkAgents(prisma: PrismaClient, telegramId: string, userId: string): Promise<string[]> {
   229‚Üí    // TelegramLink.telegramId is BigInt ‚Äî check if value fits before querying
   230‚Üí    const PG_BIGINT_MAX = BigInt('9223372036854775807');
   231‚Üí    try {
   232‚Üí        const tgBigInt = BigInt(telegramId);
   233‚Üí        if (tgBigInt < 0 || tgBigInt > PG_BIGINT_MAX) return [];
   234‚Üí    } catch {
   235‚Üí        return []; // not a valid numeric ID
   236‚Üí    }
   237‚Üí
   238‚Üí    const telegramLinks = await prisma.telegramLink.findMany({
   239‚Üí        where: { telegramId: BigInt(telegramId) },
   240‚Üí        include: { agent: { select: { id: true, agentname: true, ownerId: true } } },
   241‚Üí    });
   242‚Üí
   243‚Üí    const unownedLinks = telegramLinks.filter(row => !row.agent.ownerId);
   244‚Üí    if (unownedLinks.length === 0) return [];
   245‚Üí
   246‚Üí    const agentIds = unownedLinks.map(row => row.agent.id);
   247‚Üí
   248‚Üí    await prisma.agent.updateMany({
   249‚Üí        where: { id: { in: agentIds } },
   250‚Üí        data: { ownerId: userId, claimedAt: new Date(), claimedVia: 'telegram' },
   251‚Üí    });
   252‚Üí
   253‚Üí    return unownedLinks.map(row => row.agent.agentname);
   254‚Üí}
