   256‚Üí/**
   257‚Üí * Generate a Supabase session using admin magiclink + OTP verification.
   258‚Üí */
   259‚Üíasync function generateSupabaseSession(
   260‚Üí    supabaseAdmin: SupabaseClient,
   261‚Üí    email: string
   262‚Üí): Promise<{ access_token: string; refresh_token: string }> {
   263‚Üí    const { data: linkData, error: linkError } = await supabaseAdmin.auth.admin.generateLink({
   264‚Üí        type: 'magiclink',
   265‚Üí        email,
   266‚Üí    });
   267‚Üí
   268‚Üí    if (linkError || !linkData?.properties?.hashed_token) {
   269‚Üí        throw new Error(`Failed to generate magiclink: ${linkError?.message ?? 'no hashed_token'}`);
   270‚Üí    }
   271‚Üí
   272‚Üí    const { data: otpData, error: otpError } = await supabaseAdmin.auth.verifyOtp({
   273‚Üí        token_hash: linkData.properties.hashed_token,
   274‚Üí        type: 'magiclink',
   275‚Üí    });
   276‚Üí
   277‚Üí    if (otpError || !otpData.session) {
   278‚Üí        throw new Error(`Failed to verify OTP: ${otpError?.message ?? 'no session returned'}`);
   279‚Üí    }
   280‚Üí
   281‚Üí    return {
   282‚Üí        access_token: otpData.session.access_token,
   283‚Üí        refresh_token: otpData.session.refresh_token,
   284‚Üí    };
   285‚Üí}
