    12‚Üí/** Validate task params based on platform + actionType. Returns error string or null. */
    13‚Üíexport function validateTaskParams(task: QuestTask): string | null {
    14‚Üí    const p = task.params;
    15‚Üí    switch (task.actionType) {
    16‚Üí        case 'follow_account':
    17‚Üí            if (!p.username || !X_USERNAME_RE.test(p.username))
    18‚Üí                return `Task "${task.label}": invalid X username "${p.username || ''}"`;
    19‚Üí            break;
    20‚Üí        case 'like_post':
    21‚Üí        case 'repost':
    22‚Üí        case 'quote_post':
    23‚Üí            if (!p.postUrl || !X_POST_URL_RE.test(p.postUrl))
    24‚Üí                return `Task "${task.label}": invalid X post URL "${p.postUrl || ''}"`;
    25‚Üí            break;
    26‚Üí        case 'post':
    27‚Üí            if (!p.content || p.content.length > 280)
    28‚Üí                return `Task "${task.label}": post content required (max 280 chars)`;
    29‚Üí            break;
    30‚Üí        case 'join_server':
    31‚Üí            if (!p.inviteUrl || !DISCORD_INVITE_RE.test(p.inviteUrl))
    32‚Üí                return `Task "${task.label}": invalid Discord invite URL "${p.inviteUrl || ''}"`;
    33‚Üí            break;
    34‚Üí        case 'verify_role':
    35‚Üí            if (!p.inviteUrl || !DISCORD_INVITE_RE.test(p.inviteUrl))
    36‚Üí                return `Task "${task.label}": invalid Discord invite URL "${p.inviteUrl || ''}"`;
    37‚Üí            if (!p.roleName)
    38‚Üí                return `Task "${task.label}": role name is required`;
    39‚Üí            break;
    40‚Üí        case 'join_channel':
    41‚Üí            if (!p.channelUrl || !TELEGRAM_CHANNEL_RE.test(p.channelUrl))
    42‚Üí                return `Task "${task.label}": invalid Telegram channel "${p.channelUrl || ''}"`;
    43‚Üí            break;
    44‚Üí        default:
    45‚Üí            return `Task "${task.label}": unknown action type "${task.actionType}"`;
    46‚Üí    }
    47‚Üí    return null;
    48‚Üí}
