    50‚Üí/** Validate all tasks in an array. Returns first error or null. */
    51‚Üíexport function validateAllTasks(tasks: QuestTask[]): string | null {
    52‚Üí    for (const task of tasks) {
    53‚Üí        const err = validateTaskParams(task);
    54‚Üí        if (err) return err;
