     9‚Üíexport function startHandler(server: FastifyInstance): Composer<BotContext> {
    10‚Üí    const composer = new Composer<BotContext>();
    11‚Üí
    12‚Üí    composer.command('start', async (ctx) => {
    13‚Üí        const payload = ctx.match;
    14‚Üí
    15‚Üí        if (!payload) {
    16‚Üí            return handleBareStart(server, ctx);
    17‚Üí        }
