    19‚Üí        // Waitlist join: ?start=waitlist or ?start=ref_<code>
    20‚Üí        if (payload === 'waitlist') {
    21‚Üí            return handleWaitlistJoin(server, ctx);
    22‚Üí        }
    23‚Üí
    24‚Üí        if (payload.startsWith('ref_')) {
    25‚Üí            const referralCode = payload.slice(4); // strip "ref_" prefix
    26‚Üí            return handleWaitlistJoin(server, ctx, referralCode);
    27‚Üí        }
    28‚Üí
    29‚Üí        // Web-initiated join: wl_<accessToken> ‚Äî links pending entry to Telegram user
    30‚Üí        if (payload.startsWith('wl_')) {
    31‚Üí            const accessToken = payload.slice(3);
    32‚Üí            return handleWaitlistJoinByToken(server, ctx, accessToken);
    33‚Üí        }
    34‚Üí
