    36‚Üí        if (payload.startsWith('agent_')) {
    37‚Üí            return handleVerifyDeeplink(server, ctx, payload);
    38‚Üí        }
    39‚Üí
    40‚Üí        if (payload.startsWith('quest_')) {
    41‚Üí            return handleQuestClaimDeeplink(server, ctx, payload);
    42‚Üí        }
    43‚Üí
    44‚Üí        // Legacy backward compatibility: old deeplinks used verify_ wrapper prefix
    45‚Üí        if (payload.startsWith('verify_')) {
    46‚Üí            const rawToken = payload.slice(7); // strip "verify_" prefix ‚Üí raw hex
    47‚Üí            return handleVerifyDeeplink(server, ctx, rawToken);
    48‚Üí        }
    49‚Üí
    50‚Üí        // Treat anything else as activation code
    51‚Üí        return handleActivationCode(server, ctx, payload);
    52‚Üí    });
    53‚Üí
    54‚Üí    return composer;
    55‚Üí}
    56‚Üí
